#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int K = (1<<10)+5;
int n,m,a[105],dp[105][K][K],Ans;
char c[105][15];bool is[K];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int Count(int st){int cnt=0;while(st)cnt+=(st&1),st/=2;return cnt;}
int main(){
    n=read(),m=read();
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            cin>>c[i][j];
            a[i]|=(c[i][j]=='P'?(1<<j-1):0);
        }
    for(int st=0;st<(1<<m);st++){
        if(st&(st<<1)||st&(st<<2))continue;
        if(st&(st>>1)||st&(st>>2))continue;is[st]=1;
        if((a[1]&st)==st)dp[1][st][0]=Count(st);
    }
    for(int x=2;x<=n;x++)
        for(int i=0;i<(1<<m);i++){
            if(!is[i]||(a[x]&i)!=i)continue;
            for(int j=0;j<(1<<m);j++){
                if(!is[j]||i&j||(a[x-1]&j)!=j)continue;
                for(int k=0;k<(1<<m);k++){
                    if(!is[k]||i&k||j&k||(a[x-2]&k)!=k)continue;
                    dp[x][i][j]=max(dp[x][i][j],dp[x-1][j][k]+Count(i));
                }
            }
        }
    for(int i=0;i<(1<<m);i++)
        for(int j=0;j<(1<<m);j++)Ans=max(Ans,dp[n][i][j]);
    cout<<Ans<<"\n";
    return 0;
}
